<?php
session_start(); require 'db_connection.php'; require_once 'helpers.php'; require_login(); $conn=OpenCon(); $message=''; $userId=current_user_id();
if(isset($_POST['update'])){ $p1=$_POST['p1']??''; $p2=$_POST['p2']??''; if($p1!==$p2){$message='Passwords do not match.';} elseif(strlen($p1)<6){$message='Password must be at least 6 characters.';} else { $check=$conn->prepare("SELECT password FROM password_history WHERE user_id=? ORDER BY id DESC LIMIT 3"); $check->bind_param("i",$userId); $check->execute(); $res=$check->get_result(); $used=false; while($r=$res->fetch_assoc()){ if(password_matches($p1,$r['password'])) $used=true; } if($used){$message='Cannot use last 3 passwords.';} else { $hash=password_hash($p1,PASSWORD_DEFAULT); $upd=$conn->prepare("UPDATE users SET password=? WHERE id=?"); $upd->bind_param("si",$hash,$userId); $upd->execute(); $hist=$conn->prepare("INSERT INTO password_history (user_id,password) VALUES (?,?)"); $hist->bind_param("is",$userId,$hash); $hist->execute(); $del=$conn->prepare("DELETE FROM password_history WHERE user_id=? AND id NOT IN (SELECT id FROM (SELECT id FROM password_history WHERE user_id=? ORDER BY id DESC LIMIT 3) x)"); $del->bind_param("ii",$userId,$userId); $del->execute(); redirect('home.php'); } }}
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Update Password</title><link rel="stylesheet" href="css/style.css"></head><body><?php include 'navbar.php'; ?><div class="form-box"><h2>Update Password</h2><?php if($message):?><p class="error"><?=e($message)?></p><?php endif;?><form method="post"><label>New Password</label><input type="password" name="p1" required minlength="6"><label>Confirm Password</label><input type="password" name="p2" required minlength="6"><button name="update">Update</button></form></div></body></html>
